import { useRef, useState } from 'react'
import { motion } from 'framer-motion'

// ── Studio photo: red background, laptop, headphones ──
const STUDIO_PHOTO = ""

/**
 * Hero Section
 * - Solid red background (#ff2a2a)
 * - Studio photo on RIGHT — full height, no bg removal needed (bg already red!)
 * - Bold editorial text on LEFT
 * - Play button controls optional background video
 */
export default function Hero() {
  const videoRef = useRef(null)
  const [playing, setPlaying] = useState(false)

  const toggleVideo = () => {
    if (!videoRef.current) return
    if (playing) { videoRef.current.pause(); setPlaying(false) }
    else          { videoRef.current.play();  setPlaying(true)  }
  }

  const go = (id) => document.querySelector(id)?.scrollIntoView({ behavior: 'smooth' })

  return (
    <section
      id="home"
      className="relative min-h-screen flex overflow-hidden"
      style={{ backgroundColor: '#E60012' }}
    >
      {/* Optional background video — invisible until played */}
      <video
        ref={videoRef} muted loop playsInline
        className="absolute inset-0 w-full h-full object-cover transition-opacity duration-700"
        style={{ opacity: playing ? 0.3 : 0, zIndex: 0 }}
      >
        <source src="/hero.mp4" type="video/mp4" />
      </video>

      {/* Subtle radial shading */}
      <div className="absolute inset-0 pointer-events-none" style={{
        background: 'radial-gradient(ellipse at 10% 60%, rgba(0,0,0,0.20) 0%, transparent 60%)',
        zIndex: 2,
      }} />

      {/* Background studio photo */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          backgroundColor: '#E60012',
          backgroundImage: `url("data:image/png;base64,${STUDIO_PHOTO}")`,
          backgroundRepeat: 'no-repeat',
          backgroundSize: 'auto 100%',
          backgroundPosition: '120% 76%',
          opacity: 0.68,
          zIndex: 1,
          filter: 'brightness(1.14) contrast(1.12) saturate(1.10)',
          maskImage: 'linear-gradient(to top, rgba(255,42,42,0) 0%, rgba(255,42,42,0.12) 18%, black 26%)',
          WebkitMaskImage: 'linear-gradient(to top, rgba(255,42,42,0) 0%, rgba(255,42,42,0.12) 18%, black 26%)',
        }}
      />

      {/* ══════════ LEFT: Text content ══════════ */}
      <div className="relative z-10 flex flex-col justify-center section-pad pt-28 pb-20 flex-1 min-w-0">

        {/* Hi, I'm a */}
        <motion.p
          initial={{ opacity: 0, y: 28 }} animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.42, duration: 0.7 }}
          className="font-display text-white/80 font-normal mb-1"
          style={{ fontSize: 'clamp(1.1rem, 2.5vw, 1.7rem)' }}
        >
          Hi, I'm a
        </motion.p>

        {/* Name — large bold */}
        <motion.h1
          initial={{ opacity: 0, y: 28 }} animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.52, duration: 0.7 }}
          className="font-display font-black text-white leading-none mb-3"
          style={{ fontSize: 'clamp(3rem, 8.5vw, 7rem)', letterSpacing: '-0.03em' }}
        >
          Divya Sri
        </motion.h1>

        {/* Role — stroke outline effect */}
        <motion.h2
          initial={{ opacity: 0, y: 28 }} animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.62, duration: 0.7 }}
          className="font-display font-black leading-tight mb-7"
          style={{
            fontSize: 'clamp(1.4rem, 4vw, 3.5rem)',
            color: 'transparent',
            WebkitTextStroke: '1.5px rgba(255,255,255,0.85)',
            letterSpacing: '-0.02em',
          }}
        >
          Aspiring SEO &amp; Content<br />Marketing Professional
        </motion.h2>

        {/* Subheading */}
        <motion.p
          initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.75, duration: 0.6 }}
          className="font-body text-white/70 max-w-[420px] mb-10 leading-relaxed"
          style={{ fontSize: 'clamp(0.82rem, 1.4vw, 0.97rem)' }}
        >
          Google Analytics GA4 certified · HubSpot SEO &amp; Content Marketing ·
          Helping brands grow through data-driven content strategies.
        </motion.p>

        {/* CTA Buttons */}
        <motion.div
          initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.88, duration: 0.6 }}
          className="flex flex-wrap gap-4 mb-12"
        >
          <motion.button
            whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.97 }}
            onClick={() => go('#work')}
            className="px-7 py-3.5 bg-white text-black font-body font-semibold rounded-full text-sm shadow-lg hover:bg-black hover:text-white transition-all duration-300"
          >
            View My Work
          </motion.button>
          <motion.button
            whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.97 }}
            onClick={() => go('#contact')}
            className="px-7 py-3.5 rounded-full glass-white text-white font-body font-semibold text-sm hover:bg-white/25 transition-all duration-300"
          >
            Contact Me
          </motion.button>
        </motion.div>

      </div>


      {/* Scroll indicator */}
      <motion.button
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1.4 }}
        onClick={() => go('#about')}
        className="absolute bottom-8 left-1/2 -translate-x-1/2 z-20 hidden md:flex flex-col items-center gap-1.5 text-white/40 hover:text-white/80 transition-colors"
      >
        <span className="font-mono text-[10px] tracking-[0.3em] uppercase">Scroll</span>
        <motion.div animate={{ y: [0, 7, 0] }} transition={{ duration: 1.6, repeat: Infinity, ease: 'easeInOut' }}>
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path d="M3 5.5l5 5 5-5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
          </svg>
        </motion.div>
      </motion.button>
    </section>
  )
}
